import { useEffect, useState } from "react";
import { Navigate } from "react-router-dom";
import { auth, db } from "../firebase";
import { doc, getDoc } from "firebase/firestore";
import { onAuthStateChanged } from "firebase/auth";

export default function ProtectedRoute({ children, requiredRole }) {
  const [loading, setLoading] = useState(true);
  const [isAuth, setIsAuth] = useState(false);
  const [hasRoleAccess, setHasRoleAccess] = useState(false);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (user) => {
      if (user) {
        setIsAuth(true);
        // If the route requires a specific role, verify it in Firestore
        if (requiredRole) {
          const userDoc = await getDoc(doc(db, "users", user.uid));
          if (userDoc.exists() && userDoc.data().role === requiredRole) {
            setHasRoleAccess(true);
          } else {
            setHasRoleAccess(false);
          }
        } else {
          setHasRoleAccess(true); // No specific role needed, just auth
        }
      } else {
        setIsAuth(false);
      }
      setLoading(false);
    });

    return () => unsubscribe();
  }, [requiredRole]);

  if (loading) {
    return <div className="min-h-screen flex items-center justify-center text-gray-500">Verifying access...</div>;
  }

  // Not logged in at all
  if (!isAuth) {
    return <Navigate to="/login" replace />;
  }

  // Logged in, but trying to access a page they don't have the role for
  if (requiredRole && !hasRoleAccess) {
    return <Navigate to="/agent" replace />;
  }

  // Passed all checks
  return children;
}
